    public class Webecon {
        private string _name; private int _size = 24; private float _stroke = 2.0f;
        private string _color = "currentColor"; private string _secondaryColor = "none";
        private float _secondaryOpacity = 0.35f; private string _theme = "line";
        private string _animation = "none"; private string _trigger = "infinite";

        public Webecon(string name) { _name = name; }
        public static Webecon icon(string name) => new Webecon(name);

        public Webecon size(int s) { _size = s; return this; }
        public Webecon stroke(float s) { _stroke = s; return this; }
        public Webecon color(string c) { _color = c; return this; }
        public Webecon secondaryColor(string c) { _secondaryColor = c; return this; }
        public Webecon secondaryOpacity(float o) { _secondaryOpacity = o; return this; }
        public Webecon theme(string t) { _theme = t; return this; }
        public Webecon animation(string a) { _animation = a; return this; }
        public Webecon trigger(string t) { _trigger = t; return this; }

        public string build() => $"<webecon-icon name='{_name}' size='{_size}' stroke='{_stroke}' color='{_color}' secondary-color='{_secondaryColor}' secondary-opacity='{_secondaryOpacity}' theme='{_theme}' animation='{_animation}' animation-mode='{_trigger}'></webecon-icon>";
    }
